+export type Predicate<T extends Trait[] = Trait[]> = {
+    readonly [$predicate]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly test: (values: { [K in keyof T]: TraitRecord<T[K]> }) => boolean;
+};
+
+let predicateId = 0;
+
+/** Create a value-based entity filter from data-bearing trait dependencies. */
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    test: (values: { [K in keyof T]: TraitRecord<T[K]> }) => boolean
+): Predicate<T> {
+    for (const trait of traits) {
+        if (isRelation(trait) || trait[$internal].type === 'tag') {
+            throw new Error('Koota: Predicates only accept data-bearing traits as dependencies.');
+        }
+    }
+
+    return Object.freeze({ [$predicate]: true, id: predicateId++, traits, test }) as Predicate<T>;
+}
+
+export function isPredicate(value: unknown): value is Predicate {
+    return !!(value as Predicate | undefined)?.[$predicate];
+}
+
+export function checkPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: TraitRecord<Trait>[] = [];
+    const eid = getEntityId(entity);
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        values.push(trait[$internal].get(eid, getStore(world, trait)));
+    }
+    return predicate.test(values);
+}
